  if (!apiKey) {
    console.error("ALCHEMYST_AI_API_KEY is required");
    process.exit(1);
  }

  const client = new AlchemystAI({ apiKey });
  const runId = process.env.ZEALT_RUN_ID || 'local-run';

  const seedDocs = [
    { groups: ["eng", "v1"], key: "ENG_V1_DOC", content: "engineering notes for API version 1" },
    { groups: ["eng", "v2"], key: "ENG_V2_DOC", content: "engineering notes for API version 2" },
    { groups: ["product", "v1"], key: "PRODUCT_V1_DOC", content: "product notes for release version 1" },
    { groups: ["product", "v2"], key: "PRODUCT_V2_DOC", content: "product notes for release version 2" },
  ];

  for (const doc of seedDocs) {
    const fileName = `${doc.key}-${runId}.md`;
    try {
      await client.v1.context.add({
        context_type: "resource",
        source: "cli-seed",
        scope: "internal",
        documents: [
          {
            content: `This is a test document containing key ${doc.key}. It describes ${doc.content}.`,
          }
        ],
        metadata: {
          fileName: fileName,
          fileSize: 1024,
          fileType: "text/markdown",
          lastModified: new Date().toISOString(),
          group_name: doc.groups
        } as any
      });
      console.error(`Added doc ${fileName}`);
    } catch (e: any) {
      if (e.status === 409 || e.message?.includes('409') || e.code === 'conflict' || e.name === 'ConflictError') {
        console.error(`Doc ${fileName} already exists (409), skipping...`);
      } else {
        console.error(`Failed to add doc ${fileName}:`, e.message);
      }
    }
  }

  // Search
  try {
    const res = await client.v1.context.search({
      query: "test document containing key",
      minimum_similarity_threshold: 0.1,
      similarity_threshold: 0.1,
      body_metadata: { groupName: groups },
      metadata: "true"
    } as any);

    const matches: any[] = [];
    const seenKeys = new Set<string>();

    if (res.contexts) {
      for (const ctx of res.contexts) {
        const match = ctx.content?.match(/(ENG_V1_DOC|ENG_V2_DOC|PRODUCT_V1_DOC|PRODUCT_V2_DOC)/);
        if (match) {
          const key = match[1];
          if (!seenKeys.has(key)) {
            seenKeys.add(key);
            matches.push({ key, content: ctx.content });
          }
        }
      }
    }

    console.log(JSON.stringify(matches, null, 2));

  } catch (e: any) {
    console.error("Search error:", e.message);
    process.exit(1);
  }
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
